import{_ as e,o as t,c as r,ag as i}from"./chunks/framework.ETe_P6d1.js";const s="/kaiping-reports/assets/1.Dn2M2Sad.jpg",o="/kaiping-reports/assets/2.DmsXoppd.jpg",n="/kaiping-reports/assets/3.CfmfRA2t.jpg",l="/kaiping-reports/assets/4.DUgsiyZS.jpg",p="/kaiping-reports/assets/5.CFFDkhLK.jpg",m="/kaiping-reports/assets/6.bOsADt_D.jpg",h="/kaiping-reports/assets/7.CNJl6uwO.jpg",c="/kaiping-reports/assets/8.D8wQqZPq.jpg",g="/kaiping-reports/assets/9.DRqgZHWg.jpg",_="/kaiping-reports/assets/10.C-jyDQpi.jpg",D=JSON.parse('{"title":"开平近代建筑建造材料与构造调研报告","description":"","frontmatter":{"title":"开平近代建筑建造材料与构造调研报告"},"headers":[],"relativePath":"reports/蒋松灼/蒋松灼_蒋松灼_关于开平的调研报告.md","filePath":"reports/蒋松灼/蒋松灼_蒋松灼_关于开平的调研报告.md"}'),d={name:"reports/蒋松灼/蒋松灼_蒋松灼_关于开平的调研报告.md"};function u(f,a,q,b,k,P){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="专业调研报告内容" tabindex="-1">专业调研报告内容： <a class="header-anchor" href="#专业调研报告内容" aria-label="Permalink to &quot;专业调研报告内容：&quot;">​</a></h1><h1 id="开平近代建筑建造材料与构造调研报告" tabindex="-1"><em><strong>/<em>开平近代建筑建造材料与构造调研报告/</em></strong></em> <a class="header-anchor" href="#开平近代建筑建造材料与构造调研报告" aria-label="Permalink to &quot;***/*开平近代建筑建造材料与构造调研报告/****&quot;">​</a></h1><h3 id="——以立园、仓东村、塘口墟、赤坎古镇为例" tabindex="-1"><strong><em>/</em>——以立园、仓东村、塘口墟、赤坎古镇为例/</strong>** <a class="header-anchor" href="#——以立园、仓东村、塘口墟、赤坎古镇为例" aria-label="Permalink to &quot;***/*——以立园、仓东村、塘口墟、赤坎古镇为例/****&quot;">​</a></h3><h1 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h1><p>开平近代建筑是在侨乡社会、海外汇款、地方匠作与近代建材输入共同作用下形成的复合型建筑遗产。作为“开平碉楼与村落”世界遗产的一部分，其建筑价值并不只体现在中西合璧的外观，更体现在材料替换、结构升级与营造逻辑转变之中。联合国教科文组织指出，开平相关建筑在材料上可分为石楼、夯土楼、砖楼与钢筋混凝土楼，清楚反映出地方防御建筑从传统材料向近代材料过渡的过程。以此为背景，本文选取立园、仓东村、塘口墟、赤坎古镇四处样本，讨论其在结构材料、立面材料、连接方式与施工痕迹方面的差异与共性，进而说明：开平近代建筑的构造演变，本质上是侨乡社会对安全、体面、效率与现代性的综合回应。</p><h1 id="关键词" tabindex="-1">关键词 <a class="header-anchor" href="#关键词" aria-label="Permalink to &quot;关键词&quot;">​</a></h1><p>开平；侨乡建筑；建造材料；构造；立园；仓东村；塘口墟；赤坎古镇</p><h3 id="一、研究背景与方法" tabindex="-1"><em><strong>/<em>一、研究背景与方法/</em></strong></em> <a class="header-anchor" href="#一、研究背景与方法" aria-label="Permalink to &quot;***/*一、研究背景与方法/****&quot;">​</a></h3><p>方案书将“结构材料、立面材料、连接方式、施工痕迹”列为维度二的核心观察点，强调通过局部特写、构造草图和材料标注来完成现场记录。基于这一要求，本文将四处案例放在同一条“传统砖木—砖混/钢筋混凝土—适应性再利用”的线索中加以比较，并结合现场图像进行材料判读。第二个文档中的照片已经覆盖柱头、窗扇、墙面、屋脊、骑楼立面、粮仓群等关键细部，因此很适合支撑“材料—构造—风貌”三者之间的对应分析。</p><h3 id="二、立园-钢筋混凝土技术与园林化表皮的双重整合" tabindex="-1"><em><strong>/<em>二、立园：钢筋混凝土技术与园林化表皮的双重整合/</em></strong></em> <a class="header-anchor" href="#二、立园-钢筋混凝土技术与园林化表皮的双重整合" aria-label="Permalink to &quot;***/*二、立园：钢筋混凝土技术与园林化表皮的双重整合/****&quot;">​</a></h3><p><img src="'+s+'" alt="(())">立园由旅美华侨谢维立家族于1926—1936年间回乡兴建，是开平最具代表性的华侨私家园林之一；官方资料明确指出，园内主要建筑采用当时较先进的钢筋混凝土结构，且壁画、灰塑等装饰与园林环境共同构成其整体风貌。若从构造角度看，立园的重要性不在于“像西洋建筑”，而在于其已熟练掌握并地方化运用了钢筋混凝土这一近代技术，使其既可承担承重、抗风雨与防盗功能，又可被包装成传统园林、牌坊和别墅的形式语言。</p><p>以立园大牌坊与别墅区为例，材料层级十分清晰。官方介绍显示，大牌坊本身即为钢筋混<img src="'+o+'" alt="(())">凝土仿古建筑，柱身使用水刷石饰面，檐口则用暗红色水泥斗拱、木枋与飞椽进行“仿木化”处理；这说明其真实结构与表面表意并不一致，结构层已经现代化，而形式层仍主动保留传统秩序。换言之，立园不是简单把西式结构搬回乡村，而是利用混凝土的可塑性，制造一种“看上去仍像中国传统建筑”的现代构造。这种“结构现代、表皮传统”的做法，是开平华侨建筑成熟阶段的重要特征。</p><p><img src="'+n+'" alt="(())">立园中的乐天楼更能说明这一点。官方资料记载，该楼建于1911年，为五层钢筋混凝土结构，门窗皆为铁制，墙厚约30厘米，周边布设枪眼，兼具居住与防卫功能。这里的“铁制门窗+混凝土墙体+垂直防御设施”构成了十分明确的近代防御体系。与传统砖木民居相比，其连接方式更依赖整体浇筑或整体现代材料组合，而非单纯的榫卯与砌筑逻辑。由此可见，在立园中，材料更新并非审美趣味的附属，而是由侨乡社会对治安、防洪、身份展示和耐久性的现实需求所推动。</p><h3 id="三、仓东村-传统砖木体系中的渐进式近代化" tabindex="-1"><em><strong>/<em>三、仓东村：传统砖木体系中的渐进式近代化/</em></strong></em> <a class="header-anchor" href="#三、仓东村-传统砖木体系中的渐进式近代化" aria-label="Permalink to &quot;***/*三、仓东村：传统砖木体系中的渐进式近代化/****&quot;">​</a></h3><p>与立园相比，仓东村更适合观察“传统体系如何吸收近代材料”。斯坦福大学仓东村项目指出，20世纪前后，海外汇款促成了仓东村新住宅、祠堂、基础设施和学校的建设，说明该村的建筑更新并非个体行为，而是与侨汇网络和宗族组织联动的整体性过程。仓东项目同时表明，村中建筑与物质文化遗存主要对应晚清至民国早期阶段，这正是侨乡建筑从本土营造向中西混合过渡的关键时期。</p><p><img src="'+l+'" alt="(())"><img src="'+p+'" alt="(())">若以“仓东村祠堂—民居复合单元”为例，从现场图像及相关研究可判断，其构造底盘仍以传统砖木体系为主：墙体以青砖砌筑为核心，屋顶延续岭南坡屋面与出檐方式，室内空间则依靠木构件分隔与组织。也正因为基本体系仍属传统，仓东村的价值不在于材料彻底替换，而在于它如何在原有框架中吸收水泥抹灰、金属构件与近代构件细部，使民居、祠堂、学校等功能逐渐复合。第二个文档中的照片能看到村落门楼、厅堂、墙身、屋面与局部修缮痕迹，这些都能作为“砖木骨架+局部近代修补”的图像证据。</p><p>仓东村的另一构造特征，在于修复过程本身也是构造信息的一部分。关于“仓东计划”的研究与报道都强调，其保育并非单纯翻新，而是通过社区参与和传统工匠介入，修复灰雕、木雕、壁画等构件，同时尽量延续地方工艺与历史环境。这意味着仓东村的构造逻辑不能只看“原来怎么建”，还要看“后来怎么修”。其保育实践呈现出一种相当典型的遗产修复方法：以原有砖木体系为基础，修补而非重造，保留时间层积和工艺痕迹。这样的做法比完全重建更能体现侨乡村落建筑的历史真实性。</p><h3 id="四、塘口墟-工业遗存的结构保留与功能嵌入" tabindex="-1"><em><strong>/<em>四、塘口墟：工业遗存的结构保留与功能嵌入/</em></strong></em> <a class="header-anchor" href="#四、塘口墟-工业遗存的结构保留与功能嵌入" aria-label="Permalink to &quot;***/*四、塘口墟：工业遗存的结构保留与功能嵌入/****&quot;">​</a></h3><p><img src="'+m+'" alt="(())">塘口墟最值得从维度二切入的案例，是先锋天下粮仓书店。官方资料显示，该项目原为塘口粮管所粮仓、办公和宿舍区域，由5个建于20世纪70年代的“蒙古包式样”粮仓以及粮食加工车间、宿舍楼、办公大楼和旧农机站组成。与立园和仓东村不同，这一案例并不以传统聚落住宅为主，而属于近现代乡镇工业和公共设施体系，其材料和构造首先服务于储粮、生产和管理，而非家族居住。</p><p><img src="'+h+'" alt="(())"><img src="'+c+'" alt="(())">从构造角度看，先锋天下粮仓的关键不在新建，而在“保留原有体量与结构模块，再将文化功能插入”。现场调研感受到该项目通过，该项目通过改造旧粮仓实现活化；现场图像也显示，其白色墙体、弧形仓体、连续屋顶轮廓与旧工厂附属建筑共同构成鲜明的工业遗存形态。也就是说，该项目最重要的构造策略是对原有仓储建筑壳体与分仓逻辑的继承，而非对其进行彻底拆除重做。构造上，旧结构提供空间边界与历史识别度，新介入则承担照明、展陈、阅读和服务功能，两者形成清晰的新旧层次。</p><p>因此，塘口墟所体现的并不是侨乡建筑早期的建材输入，而是后工业乡村空间如何通过“轻介入、强识别”的方式继续使用原有建筑。与立园强调混凝土技术的体面表达不同，塘口墟更强调结构保留与空间再编程；与仓东村强调工艺修补不同，塘口墟更重视旧工业骨架与当代文化业态之间的兼容性。这说明在开平的当代遗产实践中，材料与构造已不再只关乎“如何建”，也关乎“如何继续用”。</p><h3 id="五、赤坎古镇-连续骑楼界面的结构秩序" tabindex="-1"><em><strong>/<em>五、赤坎古镇：连续骑楼界面的结构秩序/</em></strong></em> <a class="header-anchor" href="#五、赤坎古镇-连续骑楼界面的结构秩序" aria-label="Permalink to &quot;***/*五、赤坎古镇：连续骑楼界面的结构秩序/****&quot;">​</a></h3><p><img src="'+g+'" alt="(())"><img src="'+_+'" alt="(())">赤坎古镇现存600多座骑楼，形成约3公里连续街区，是全国规模最大、界面最连续、保存最完整的侨乡骑楼建筑群之一。其建筑兴盛于近代商贸发展与华侨回流背景之下，类型上明显区别于乡村碉楼和私人园林，更接近商业街道建筑的城市化构造逻辑。骑楼一层退让形成柱廊灰空间，上层承担居住、办公或仓储功能，这种“下店上宅”的组织方式决定了其结构必须同时应对商业展示、气候遮蔽与连续界面三重需求。</p><p>从现场照片判断，赤坎骑楼街区的主体体系以砖混或钢筋混凝土近代体系为主，连续柱廊、楼板、阳台、檐口和山花共同形成重复而又有差异的街道节奏。现场调研感受到该项目通过，开平侨乡建筑广泛吸纳钢筋、水泥等近代材料，而骑楼正是这种材料现代化在商业街建筑中的集中体现。其立面多采用抹灰、水泥线脚、金属栏杆和可开启窗扇，既满足街道展示，也强化立面连续性。从维度二看，赤坎最重要的价值不在单体，而在于一整条街如何通过相近的柱廊尺度、楼层模数和材料表皮形成稳定的公共秩序。</p><h3 id="六、比较分析-从-安全建造-到-持续使用" tabindex="-1"><em><strong>/<em>六、比较分析：从“安全建造”到“持续使用”/</em></strong></em> <a class="header-anchor" href="#六、比较分析-从-安全建造-到-持续使用" aria-label="Permalink to &quot;***/*六、比较分析：从“安全建造”到“持续使用”/****&quot;">​</a></h3><p>四处案例显示，开平近代建筑的材料与构造演化大致可以概括为三个阶段。第一，仓东村代表传统砖木体系吸纳近代构件的过渡阶段；第二，立园代表钢筋混凝土技术被熟练掌握并审美化包装的成熟阶段；第三，塘口墟与赤坎古镇则代表遗产建筑在当代通过修缮、再利用与功能嵌入而获得新生命的阶段。其共同点在于：材料的变化总是与社会功能同步变化，防卫、居住、商业、展示和文旅都在结构层面留下了清晰痕迹。</p><p>从调研角度说，维度二并不只是辨认“这是砖墙还是混凝土”，更重要的是通过材料判断建筑所处的历史阶段、技术来源和使用逻辑。开平案例的独特之处就在于，它把侨汇输入、外来建材、本地工匠、岭南气候与乡土防御需求压缩在同一套构造语言之中。因此，对其建造材料与构造的研究，最终指向的不是纯技术史，而是侨乡社会如何借由建筑完成现代化的一种地方表达。</p><h3 id="参考文献" tabindex="-1"><em><strong>/<em>参考文献/</em></strong></em> <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;***/*参考文献/****&quot;">​</a></h3><ol><li>UNESCO World Heritage Centre. <em>Kaiping Diaolou and Villages</em>.</li><li>Batto, Patricia R. S. 2006. <em>The Diaolou of Kaiping (1842–1937): Buildings for Dangerous Times</em>. China Perspectives.</li><li>Voss, Barbara L., J. Ryan Kennedy, Selia Jinhua Tan, and Laura W. Ng. 2018. <em>The Archaeology of Home: Qiaoxiang and Non-State Actors in the Archaeology of the Chinese Diaspora</em>. <em>American Antiquity</em> 83(3): 407–426.</li><li>Tan, Selia Jinhua, and Zheng Dehua. 2012. <em>The Architectural Style and Cultural Connotation of Lu Mansions in Kaiping of Guangdong</em>. <em>Advanced Materials Research</em> 598: 12–21.</li><li>谭金花. 2015.《乡村文化遗产保育与发展的研究及实践探索——以广东开平仓东村为例》.《南方建筑》2015(1): 18–23.</li><li>谭金花. 2016.《碉楼与庐：五邑侨乡建筑风格的演变及文化根源》.《五邑大学学报（社会科学版）》18(1): 1–7.</li><li>开平市人民政府、塘口镇人民政府有关立园与先锋天下粮仓书店的官方介绍。</li><li>赤坎镇人民政府有关赤坎古镇与骑楼街区的官方介绍。</li></ol>',29)])])}const S=e(d,[["render",u]]);export{D as __pageData,S as default};
